        double tr=(x1_re)+(x3_re), ti=(x1_im)+(x3_im);
        double ur=(x1_re)-(x3_re), ui=(x1_im)-(x3_im);
        x0_re=(sr)+(tr); x0_im=(si)+(ti);
        x2_re=(sr)-(tr); x2_im=(si)-(ti);
        x1_re=(dr)-(ui); x1_im=(di)+(ur);
