        double d1r=(x1_re)-(x4_re), d1i=(x1_im)-(x4_im);
        double s2r=(x2_re)+(x3_re), s2i=(x2_im)+(x3_im);
        double d2r=(x2_re)-(x3_re), d2i=(x2_im)-(x3_im);
        double ss_r=(s1r)+(s2r), ss_i=(s1i)+(s2i);
        double sd_r=(s1r)-(s2r), sd_i=(s1i)-(s2i);
        double t0r=(x0_re)-(cD)*(ss_r), t0i=(x0_im)-(cD)*(ss_i);
        x0_re=(x0_re)+(ss_r); x0_im=(x0_im)+(ss_i);
        double p1r=(cA)*(sd_r)+(t0r), p1i=(cA)*(sd_i)+(t0i);
        double p2r=(t0r)-(cA)*(sd_r), p2i=(t0i)-(cA)*(sd_i);
        double qar=(cC)*(d2i)+((cB)*(d1i)), qai=(cC)*(d2r)+((cB)*(d1r));
        double qbr=(cB)*(d2i)-((cC)*(d1i)), qbi=(cB)*(d2r)-((cC)*(d1r));
        x1_re=(p1r)-(qar); x1_im=(p1i)+(qai);
