        double ss_r=(s1r)+(s2r), ss_i=(s1i)+(s2i);
        double sd_r=(s1r)-(s2r), sd_i=(s1i)-(s2i);
        double t0r=(x0_re)-(cD)*(ss_r), t0i=(x0_im)-(cD)*(ss_i);
